// Send Pendientes 8AM — respuesta a leads sin atencion
const pendientes = [{"phone": "522281388295", "nombre": "Liz", "state": "NEW", "lastText": "Hola, quiero saber si mi hijo califica para InnovaKids.", "lastIn": "2026-04-30T00:00:52.491Z"}, {"phone": "59173085464", "nombre": "Dam", "state": "NEW", "lastText": "Buenas noches tenia programada mi reunión para hoy a las 20:", "lastIn": "2026-04-30T00:44:18.932Z"}];
const YCLOUD_KEY = "b0bdbae389901432af2b47d9c6a4dcbe";
const FROM       = "56964754219";
const N8N_URL    = "https://quirky-thompson.74-208-238-121.plesk.page";
const WF_ID_SELF = $workflow.id;

const resultados = [];

for (const lead of pendientes) {
  const n  = lead.nombre ? lead.nombre : '';
  const saludo = n ? ('Hola ' + n + '! ') : 'Hola! ';

  // Mensaje diferenciado segun contexto del lead
  let msg;
  const lastText = (lead.lastText || '').toLowerCase();
  if (lastText.includes('reunion') || lastText.includes('reunión') || lastText.includes('programada')) {
    msg = saludo + 'Soy Francisca de InnovaKids 🙋\u200d\u2640\ufe0f\n' +
          'Vi que escribiste sobre tu reunión y quiero asegurarme de que quedaste bien atendido/a.\n' +
          '¿Pudiste agendar tu evaluación gratuita? ¿En qué te puedo ayudar?';
  } else if (lastText.includes('pagar') || lastText.includes('pague') || lastText.includes('300') || lastText.includes('pagué')) {
    msg = saludo + 'Soy Francisca de InnovaKids 😊\n' +
          'Vi tu mensaje y quiero resolverlo personalmente.\n' +
          '¿Me cuentas qué pasó para ayudarte de inmediato?';
  } else {
    msg = saludo + 'Soy Francisca de InnovaKids 🙋\u200d\u2640\ufe0f\n' +
          'Vi que me escribiste y quiero asegurarme de responderte.\n' +
          '¿En qué te puedo ayudar con el programa de IA para tu hijo/a?';
  }

  try {
    const resp = await $helpers.httpRequest({
      method:  'POST',
      url:     'https://api.ycloud.com/v2/whatsapp/messages',
      headers: { 'Content-Type': 'application/json', 'X-API-Key': YCLOUD_KEY },
      body: JSON.stringify({ from: FROM, to: lead.phone, type: 'text', text: { body: msg } }),
    });
    console.log('[SendPendientes] OK', lead.phone, resp.id || '');
    resultados.push({ phone: lead.phone, status: 'enviado', nombre: lead.nombre, msgId: resp.id || '' });
  } catch(e) {
    console.log('[SendPendientes] ERR', lead.phone, e.message);
    resultados.push({ phone: lead.phone, status: 'error', error: e.message.slice(0,100) });
  }

  await new Promise(r => setTimeout(r, 2000));
}

// Auto-desactivar este workflow
try {
  await $helpers.httpRequest({
    method: 'POST', url: N8N_URL + '/rest/login',
    headers: { 'Content-Type': 'application/json', 'browser-id': 'pendientes-self' },
    body: JSON.stringify({ emailOrLdapLoginId: 'ricardo.farias.q@gmail.com', password: 'Gaspi1712#' }),
  });
  await $helpers.httpRequest({
    method: 'PATCH', url: N8N_URL + '/rest/workflows/' + WF_ID_SELF,
    headers: { 'Content-Type': 'application/json', 'browser-id': 'pendientes-self' },
    body: JSON.stringify({ active: false }),
  });
  console.log('[SendPendientes] Workflow auto-desactivado.');
} catch(e) {
  console.log('[SendPendientes] No se pudo auto-desactivar:', e.message);
}

const ok = resultados.filter(r => r.status === 'enviado').length;
console.log('[SendPendientes] Total:', ok, '/', pendientes.length, 'enviados.');
return resultados.map(r => ({ json: r }));

